proof_block:
// The proof fn's ensures is structured `({ BC_post1 && BC_post2 }) ==>
// det_<f>_equal(r1, r2, post1_self_, post2_self_)`.  BC is the antecedent
// of an implication — *not* a hypothesis in the proof body.  Verus only has
// the function's `requires` in scope (none of which mention `post1_self_`
// or `post2_self_`), so the previous attempt's bare top-level
// `assert(forall|p: Pcid| ... post1_self_@[p as int] =~= pre_self_@[p as int])`
// was unprovable and Verus rejected it.
//
// Fix: place the trigger-instantiation reasoning *inside* a proof-mode
// `if BC_conjuncts { ... }` block.  Inside the branch, the conjuncts of
// the LHS are hypotheses, so the helper lemma's requires are met and the
// per-projection equalities at the `pcid` index follow from transitivity
// through `pre_self_`.  Verus's flow-sensitive analysis carries the facts
// proved inside the branch out to the merge as `cond ==> body_facts`; at
// ensures-discharge time z3 has the full LHS, the `if` guard is implied,
// and the merged facts become available for closing the determinism check.

if (forall|p: Pcid|
        #![trigger post1_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < PCID_MAX && p != pcid ==> post1_self_@[p as int] =~= pre_self_@[p as int])
    && (forall|p: Pcid|
        #![trigger post2_self_@[p as int]]
        #![trigger pre_self_@[p as int]]
        0 <= p < PCID_MAX && p != pcid ==> post2_self_@[p as int] =~= pre_self_@[p as int])
    && post1_self_@[pcid as int].is_Some()
    && post2_self_@[pcid as int].is_Some()
    && post1_self_@[pcid as int].unwrap().pcid == pre_self_@[pcid as int].unwrap().pcid
    && post2_self_@[pcid as int].unwrap().pcid == pre_self_@[pcid as int].unwrap().pcid
    && post1_self_@[pcid as int].unwrap().kernel_l4_end
        == pre_self_@[pcid as int].unwrap().kernel_l4_end
    && post2_self_@[pcid as int].unwrap().kernel_l4_end
        == pre_self_@[pcid as int].unwrap().kernel_l4_end
    && (post1_self_@[pcid as int].unwrap().page_closure()
        =~= pre_self_@[pcid as int].unwrap().page_closure().insert(page_map_ptr))
    && (post2_self_@[pcid as int].unwrap().page_closure()
        =~= pre_self_@[pcid as int].unwrap().page_closure().insert(page_map_ptr))
    && (post1_self_@[pcid as int].unwrap().mapping_4k()
        =~= pre_self_@[pcid as int].unwrap().mapping_4k())
    && (post2_self_@[pcid as int].unwrap().mapping_4k()
        =~= pre_self_@[pcid as int].unwrap().mapping_4k())
    && (post1_self_@[pcid as int].unwrap().mapping_2m()
        =~= pre_self_@[pcid as int].unwrap().mapping_2m())
    && (post2_self_@[pcid as int].unwrap().mapping_2m()
        =~= pre_self_@[pcid as int].unwrap().mapping_2m())
    && (post1_self_@[pcid as int].unwrap().mapping_1g()
        =~= pre_self_@[pcid as int].unwrap().mapping_1g())
    && (post2_self_@[pcid as int].unwrap().mapping_1g()
        =~= pre_self_@[pcid as int].unwrap().mapping_1g())
    && (post1_self_@[pcid as int].unwrap().kernel_entries
        =~= pre_self_@[pcid as int].unwrap().kernel_entries)
    && (post2_self_@[pcid as int].unwrap().kernel_entries
        =~= pre_self_@[pcid as int].unwrap().kernel_entries)
{
    // Discharge the non-pcid pointwise equality via the helper lemma.
    lemma_det_pagetable_array_create_pagetable_l2_entry_t_nonpcid_eq(
        pre_self_, pcid, post1_self_, post2_self_);

    // Restate the non-pcid pointwise equality inline so its trigger shape
    // (`post1_self_@[p], post2_self_@[p]`) is anchored at the final
    // ensures-discharge.
    assert forall|p: int| 0 <= p < PCID_MAX && p != pcid as int implies
        post1_self_@[p] == post2_self_@[p]
    by {
        let pu: Pcid = p as Pcid;
        assert(0 <= pu < PCID_MAX);
        assert(pu != pcid);
        assert(post1_self_@[pu as int] =~= pre_self_@[pu as int]);
        assert(post2_self_@[pu as int] =~= pre_self_@[pu as int]);
    }

    // At the `pcid` index every projection of the inner `PageTable` is
    // pinned through `pre_self_` to the same value on both runs.  These
    // are *not* full structural equalities of the underlying `PageTable`
    // — that would require pinning all `Ghost` / `Tracked` fields — but
    // they give z3 the projection-level trigger anchors it needs to
    // discharge the per-projection conjuncts of `det_..._equal` at the
    // final implication.
    assert(post1_self_@[pcid as int].is_Some());
    assert(post2_self_@[pcid as int].is_Some());
    assert(post1_self_@[pcid as int].unwrap().pcid
        == post2_self_@[pcid as int].unwrap().pcid);
    assert(post1_self_@[pcid as int].unwrap().kernel_l4_end
        == post2_self_@[pcid as int].unwrap().kernel_l4_end);
    assert(post1_self_@[pcid as int].unwrap().page_closure()
        =~= post2_self_@[pcid as int].unwrap().page_closure());
    assert(post1_self_@[pcid as int].unwrap().mapping_4k()
        =~= post2_self_@[pcid as int].unwrap().mapping_4k());
    assert(post1_self_@[pcid as int].unwrap().mapping_2m()
        =~= post2_self_@[pcid as int].unwrap().mapping_2m());
    assert(post1_self_@[pcid as int].unwrap().mapping_1g()
        =~= post2_self_@[pcid as int].unwrap().mapping_1g());
    assert(post1_self_@[pcid as int].unwrap().kernel_entries
        =~= post2_self_@[pcid as int].unwrap().kernel_entries);
}

helper_lemmas:
// Helper: starting from the two per-`p` `forall|p|` ensures (whose triggers
// are disjoint — `post1_self_@[p]` vs `post2_self_@[p]` — so z3 never lines
// them up on its own) derive a *single* pointwise non-pcid equality
// `post1_self_@[p] == post2_self_@[p]`. Inside the `assert forall` body we
// instantiate both ensures at the same `pu` so the chain
// `post1_self_@[pu] =~= pre_self_@[pu] =~= post2_self_@[pu]` becomes
// available to z3.
proof fn lemma_det_pagetable_array_create_pagetable_l2_entry_t_nonpcid_eq(
    pre_self_: Array<Option<PageTable>, PCID_MAX>,
    pcid: Pcid,
    post1_self_: Array<Option<PageTable>, PCID_MAX>,
    post2_self_: Array<Option<PageTable>, PCID_MAX>,
)
    requires
        forall|p: Pcid|
            #![trigger post1_self_@[p as int]]
            #![trigger pre_self_@[p as int]]
            0 <= p < PCID_MAX && p != pcid ==> post1_self_@[p as int] =~= pre_self_@[p as int],
        forall|p: Pcid|
            #![trigger post2_self_@[p as int]]
            #![trigger pre_self_@[p as int]]
            0 <= p < PCID_MAX && p != pcid ==> post2_self_@[p as int] =~= pre_self_@[p as int],
    ensures
        forall|p: int|
            #![trigger post1_self_@[p], post2_self_@[p]]
            0 <= p < PCID_MAX && p != pcid as int ==> post1_self_@[p] == post2_self_@[p],
{
    assert forall|p: int|
        0 <= p < PCID_MAX && p != pcid as int implies
        post1_self_@[p] == post2_self_@[p]
    by {
        let pu: Pcid = p as Pcid;
        assert(0 <= pu < PCID_MAX);
        assert(pu != pcid);
        // Fire both ensures triggers at the same `pu`.
        assert(post1_self_@[pu as int] =~= pre_self_@[pu as int]);
        assert(post2_self_@[pu as int] =~= pre_self_@[pu as int]);
    }
}
